package com.teamspace.teamspace.taskactivity.controller;
import org.springframework.security.core.Authentication; import org.springframework.web.bind.annotation.*; import com.teamspace.teamspace.common.ApiResponse; import com.teamspace.teamspace.taskactivity.dto.TaskTimelinePage; import com.teamspace.teamspace.taskactivity.service.TaskActivityService; import lombok.RequiredArgsConstructor;
@RestController @RequestMapping("/api/tasks/{taskId}/activities") @RequiredArgsConstructor public class TaskActivityController {private final TaskActivityService service;@GetMapping public ApiResponse<TaskTimelinePage> get(@PathVariable Long taskId,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size,Authentication a){return ApiResponse.success("Lay lich su task thanh cong",service.timeline(taskId,page,size,a));}}
